CREATE OR REPLACE VIEW stock_01_14_20_por_talle_vASSELECT TOP 100 cod_articulo, cod_color_articulo, Talle, cantidad, cant_1FROM (SELECT articulos.cod_articulo, colores_por_articulo.cod_color_articulo, IFNULL(stock_consolidad FROM stock WHERE (cod_almacen = '01') OR (cod_almacen = '14') OR _articulo ON articulos.cod_articulo = colores_por_articulo.cod_articulo UNION ALL SELECT articulos.cod_articulo, colores_por_articulo.cod_co FROM stock WHERE (cod_almacen = '01') OR (cod_almacen = '1ores_por_articulo.cod_color_articulo ON articulos.cod_articulo = colores_por_articulo.cod_articulo) DERIVEDTBLWHERE (NOT (Talle IS NULL));;
